from dataclasses import dataclass
from abc import ABC, abstractmethod
import anthropic
import json
import time
from typing import Protocol

# --- Canonical types ---
@dataclass
class EmailDraftRequest:
    user_context: dict
    topic: str

@dataclass
class EmailDraftResponse:
    subject: str
    body: str
    input_tokens: int
    output_tokens: int

# --- LLM Gateway interface ---
class EmailGateway(Protocol):
    def draft(self, req: EmailDraftRequest) -> EmailDraftResponse: ...

# --- Prompt + parsing layer (LLM Gateway implementation) ---
class AnthropicEmailGateway:
    def __init__(self, adapter: "ModelAdapter", prompt_template: str):
        self._adapter = adapter
        self._template = prompt_template

    def draft(self, req: EmailDraftRequest) -> EmailDraftResponse:
        prompt = self._template.format(
            user_context=json.dumps(req.user_context),
            topic=req.topic,
        )
        raw = self._adapter.complete(prompt, max_tokens=800)
        return self._parse(raw)

    def _parse(self, raw: "ModelResponse") -> EmailDraftResponse:
        text = raw.text
        if text.startswith("Subject:"):
            parts = text.split("\n", 1)
            subject = parts[0].replace("Subject:", "").strip()
            body = parts[1].strip() if len(parts) > 1 else ""
        else:
            subject = "Re: " + text[:60]
            body = text
        return EmailDraftResponse(
            subject=subject,
            body=body,
            input_tokens=raw.input_tokens,
            output_tokens=raw.output_tokens,
        )

# --- Model Adapter (one per provider) ---
@dataclass
class ModelResponse:
    text: str
    input_tokens: int
    output_tokens: int

class ModelAdapter(ABC):
    @abstractmethod
    def complete(self, prompt: str, max_tokens: int) -> ModelResponse: ...

class AnthropicAdapter(ModelAdapter):
    def __init__(self, model: str = "claude-opus-4-5"):
        self._client = anthropic.Anthropic()
        self._model = model

    def complete(self, prompt: str, max_tokens: int) -> ModelResponse:
        resp = self._client.messages.create(
            model=self._model,
            max_tokens=max_tokens,
            messages=[{"role": "user", "content": prompt}],
        )
        return ModelResponse(
            text=resp.content[0].text,
            input_tokens=resp.usage.input_tokens,
            output_tokens=resp.usage.output_tokens,
        )

# --- Retry wrapper (separate concern) ---
def with_retry(fn, max_attempts: int = 3, base_delay: float = 1.0):
    for attempt in range(max_attempts):
        try:
            return fn()
        except anthropic.APIError:
            if attempt == max_attempts - 1:
                raise
            time.sleep(base_delay * (2 ** attempt))

# --- Business logic ---
PROMPT_TEMPLATE = """You are a professional email writer.
User context: {user_context}
Topic: {topic}
Write a professional email starting with 'Subject: <subject line>'.""".strip()

adapter = AnthropicAdapter()
gateway = AnthropicEmailGateway(adapter, PROMPT_TEMPLATE)

def draft_email(user_context: dict, topic: str) -> str:
    req = EmailDraftRequest(user_context=user_context, topic=topic)
    result = with_retry(lambda: gateway.draft(req))
    return json.dumps({"subject": result.subject, "body": result.body})

